import { useState, useMemo, useEffect, useCallback } from 'react';
import { useParams, useNavigate, useLocation } from 'react-router-dom';
import {
  ShieldCheck,
  Users,
  ChevronLeft,
  Loader2,
  CheckCircle2,
  Search,
  UserCheck,
  UserPlus,
  Lock,
  ArrowRight,
  ShieldAlert,
  Trash2,
  RotateCcw,
  Eye,
  Plus,
  Pencil,
  Eraser,
  Link,
  Unlink,
  Power,
  PowerOff,
  BadgeCheck,
  Flag,
  Ban,
  CircleMinus,
  Settings2,
  HelpCircle,
  type LucideIcon,
} from 'lucide-react';
import { roleService } from '@/api/auth/roleService';
import { permissionService } from '@/api/auth/permissionService';
import { useQuery, useQueryClient } from '@tanstack/react-query';
import { HarmonyTable, type HarmonyColumn } from '@/components/ui/harmony-table';
import { Tooltip, TooltipContent, TooltipProvider, TooltipTrigger } from '@/shadcn/components/ui/tooltip';
import { queryKeys } from '@/lib/queryKeys';
import { ROUTES } from '@/lib/routes';
import { toast } from 'sonner';
import { PermissionGate } from '@/components/shared/PermissionGate';
import { PERMISSIONS } from '@/constants/permissions';
import { Button } from '@/shadcn/components/ui/button';
import { Tabs, TabsList, TabsTrigger, TabsContent } from '@/shadcn/components/ui/tabs';
import { AddUsersToRoleDialog } from '@/features/roles/components/AddUsersToRoleDialog';
import { HarmonyAlertDialog } from '@/components/ui/harmony-alert-dialog';

const ACTION_ICONS: Record<string, LucideIcon> = {
  Read:       Eye,
  Create:     Plus,
  Update:     Pencil,
  Delete:     Trash2,
  HardDelete: Eraser,
  Allocate:   Link,
  Deallocate: Unlink,
  Restore:    RotateCcw,
  Activate:   Power,
  Deactivate: PowerOff,
  Approve:    BadgeCheck,
  Finalize:   Flag,
  Reject:     Ban,
  Consume:    CircleMinus,
  Manage:     Settings2,
};
const DEFAULT_ACTION_ICON: LucideIcon = HelpCircle;

interface PermissionItem {
  id: string;
  displayName: string;
  resource: string;
  description?: string;
  action?: string;
  isAdministratorsOnly?: boolean;
}

interface PermissionGroup {
  resource: string;
  permissions: PermissionItem[];
}

export default function RoleConfiguration() {
  const { roleId } = useParams();
  const navigate = useNavigate();
  const location = useLocation();
  const queryClient = useQueryClient();
  const [activeTab, setActiveTab] = useState<'users' | 'permissions'>('users');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [rolePerms, setRolePerms] = useState<Record<string, boolean>>({});
  const [savedRolePerms, setSavedRolePerms] = useState<Record<string, boolean>>({});
  const [searchQuery, setSearchQuery] = useState('');
  const [addUsersOpen, setAddUsersOpen] = useState(false);
  const [removeTarget, setRemoveTarget] = useState<{ id: string; fullName: string | null } | null>(null);
  const [isRemoving, setIsRemoving] = useState(false);
  const [permFilterValues, setPermFilterValues] = useState<Record<string, string>>({});

  const { data: role, isLoading: roleLoading } = useQuery({
    queryKey: queryKeys.roles.byId(roleId!),
    queryFn: () => roleService.getRoleById(roleId!),
    enabled: !!roleId
  });

  const isBuiltIn = role?.isBuiltIn ?? false;

  const { data: permissionGroups = [], isLoading: permsLoading } = useQuery<PermissionGroup[]>({
    queryKey: queryKeys.permissionsCatalog(),
    queryFn: () => permissionService.getAllPermissionsGrouped(),
    staleTime: Infinity,
  });

  const { data: initialPermsData, isLoading: initialPermsLoading } = useQuery<{ assignments?: Array<{ permissionId: string; isGranted: boolean }> }>({
    queryKey: queryKeys.roles.permissions(roleId!),
    queryFn: async () => {
      const data = await roleService.getRolePermissions(roleId!) as { assignments?: Array<{ permissionId: string; isGranted: boolean }> } | null;
      return data ?? {};
    },
    enabled: !!roleId
  });

  useEffect(() => {
    if (!initialPermsData) return;
    const permMap: Record<string, boolean> = {};
    if (initialPermsData.assignments) {
      initialPermsData.assignments.forEach((a) => {
        permMap[a.permissionId] = a.isGranted;
      });
    }
    setRolePerms(permMap);
    setSavedRolePerms(permMap);
  }, [initialPermsData]);

  const { data: roleUsers = [], isLoading: usersLoading } = useQuery({
    queryKey: queryKeys.roles.users(roleId!),
    queryFn: () => roleService.getRoleUsers(roleId!),
    enabled: !!roleId,
  });

  const existingUserIds = useMemo(() => new Set(roleUsers.map(u => u.id)), [roleUsers]);

  const usersInRole = useMemo(() => {
    const sorted = [...roleUsers].sort((a, b) => (a.fullName ?? '').localeCompare(b.fullName ?? ''));
    if (!searchQuery) return sorted;
    const q = searchQuery.toLowerCase();
    return sorted.filter(u =>
      u.fullName?.toLowerCase().includes(q) ||
      u.email?.toLowerCase().includes(q)
    );
  }, [roleUsers, searchQuery]);

  const isAdministratorsRole = role?.name === 'Administrators';

  // IDs of permissions structurally locked to Administrators.
  const adminOnlyIds = useMemo(() => {
    const ids = new Set<string>();
    permissionGroups.forEach((g) =>
      g.permissions.forEach((p) => {
        if (p.isAdministratorsOnly) ids.add(p.id);
      })
    );
    return ids;
  }, [permissionGroups]);

  // Compute the visible selection state:
  // - Administrators role: admin-only permissions are always checked (structural lock is permanent)
  // - Other roles: admin-only permissions are always unchecked (grant has no effect)
  const effectiveSelectedRows = useMemo(() => {
    const base = new Set(Object.keys(rolePerms).filter(id => rolePerms[id]));
    if (isAdministratorsRole) {
      adminOnlyIds.forEach(id => base.add(id));
    } else {
      adminOnlyIds.forEach(id => base.delete(id));
    }
    return base;
  }, [rolePerms, isAdministratorsRole, adminOnlyIds]);

  const handlePermissionSelectionChange = useCallback((newSelection: Set<string | number>) => {
    if (isBuiltIn) return;
    const newPerms: Record<string, boolean> = {};
    permissionGroups.forEach((g) => {
      g.permissions.forEach((p) => {
        newPerms[p.id] = newSelection.has(p.id);
      });
    });
    setRolePerms(newPerms);
  }, [isBuiltIn, permissionGroups]);

  const isDirty = useMemo(() => {
    const keys = new Set([...Object.keys(rolePerms), ...Object.keys(savedRolePerms)]);
    for (const k of keys) {
      if (!!rolePerms[k] !== !!savedRolePerms[k]) return true;
    }
    return false;
  }, [rolePerms, savedRolePerms]);

  const handleResetPermissions = useCallback(() => {
    setRolePerms({ ...savedRolePerms });
  }, [savedRolePerms]);

  const allPermissionRows = useMemo(
    () => permissionGroups.flatMap((g) => g.permissions.map((p) => ({ ...p, resource: g.resource, id: p.id }))),
    [permissionGroups]
  );

  const filteredPermissionRows = useMemo(() => {
    let rows = allPermissionRows;
    if (permFilterValues.resource) rows = rows.filter(r => r.resource === permFilterValues.resource);
    if (permFilterValues.action) rows = rows.filter(r => r.action === permFilterValues.action);
    if (permFilterValues.selected === 'selected') rows = rows.filter(r => effectiveSelectedRows.has(r.id));
    if (permFilterValues.selected === 'unselected') rows = rows.filter(r => !effectiveSelectedRows.has(r.id));
    return rows;
  }, [allPermissionRows, permFilterValues, effectiveSelectedRows]);

  const permFilterDefs = useMemo(() => {
    const resources = [...new Set(permissionGroups.map(g => g.resource))].sort();
    const actions = [...new Set(allPermissionRows.map(r => r.action).filter(Boolean) as string[])].sort();
    return [
      {
        param: 'resource',
        label: 'Module',
        type: 'select' as const,
        options: resources.map(r => ({ value: r, label: r })),
      },
      {
        param: 'action',
        label: 'Action',
        type: 'select' as const,
        options: actions.map(a => {
          const Icon = ACTION_ICONS[a] ?? DEFAULT_ACTION_ICON;
          return { value: a, label: a, icon: <Icon size={12} className="text-muted-foreground shrink-0" /> };
        }),
      },
      {
        param: 'selected',
        label: 'Status',
        type: 'select' as const,
        options: [
          { value: 'selected', label: 'Selected' },
          { value: 'unselected', label: 'Unselected' },
        ],
      },
    ];
  }, [permissionGroups, allPermissionRows]);

  const harmonyPermissionColumns = useMemo((): HarmonyColumn<PermissionItem>[] => [
    { key: 'resource', header: 'Module Namespace', width: 200 },
    {
      key: 'displayName',
      header: 'Permission Name',
      width: 250,
      renderCell: ({ row }) => (
        <div className="flex items-center gap-2 min-w-0">
          <span className="truncate">{row.displayName}</span>
          {row.isAdministratorsOnly && (
            <TooltipProvider>
              <Tooltip>
                <TooltipTrigger asChild>
                  <span className="inline-flex items-center gap-1 px-1.5 py-0.5 rounded text-[10px] font-bold bg-primary/10 text-primary border border-primary/20 shrink-0 cursor-help">
                    <ShieldAlert size={9} />
                    Admin Only
                  </span>
                </TooltipTrigger>
                <TooltipContent>
                  {isAdministratorsRole
                    ? 'Administrators always hold this permission via structural lock. It cannot be revoked.'
                    : 'Structurally locked to Administrators — granting this to role has no effect.'}
                </TooltipContent>
              </Tooltip>
            </TooltipProvider>
          )}
        </div>
      )
    },
    {
      key: 'action',
      header: 'Action',
      width: 130,
      renderCell: ({ row }) => {
        if (!row.action) return null;
        const Icon = ACTION_ICONS[row.action] ?? DEFAULT_ACTION_ICON;
        return (
          <div className="flex items-center gap-1.5">
            <Icon size={13} className="text-muted-foreground shrink-0" />
            <span>{row.action}</span>
          </div>
        );
      }
    },
    { key: 'description', header: 'Business Logic Description', fill: true },
  ], [isAdministratorsRole]);

  const handleRemoveUser = async () => {
    if (!removeTarget || !roleId) return;
    setIsRemoving(true);
    try {
      await roleService.removeUserFromRole(roleId, removeTarget.id);
      queryClient.invalidateQueries({ queryKey: queryKeys.roles.users(roleId) });
      toast.success('User removed from role.');
      setRemoveTarget(null);
    } catch {
      toast.error('Failed to remove user from role.');
    } finally {
      setIsRemoving(false);
    }
  };

  const handleSavePermissions = async () => {
    if (!roleId) return;
    setIsSubmitting(true);
    try {
      const assignments = Object.keys(rolePerms)
        .map(id => ({
          permissionId: id,
          isGranted: rolePerms[id]
        }));

      await roleService.setRolePermissions(roleId!, assignments);
      queryClient.invalidateQueries({ queryKey: queryKeys.roles.permissions(roleId!) });
      setSavedRolePerms({ ...rolePerms });
      toast.success('Permissions updated successfully');
    } catch {
      toast.error('Failed to update permissions');
    } finally {
      setIsSubmitting(false);
    }
  };

  if (roleLoading) {
    return (
      <div className="flex h-[80vh] items-center justify-center">
        <Loader2 className="animate-spin text-primary" size={48} />
      </div>
    );
  }

  return (
    <div className="page-wrapper flex flex-col" style={{ gap: 'var(--section-padding)' }}>

      {/* Header */}
      <div className="flex items-center gap-3">
        <button
          onClick={() => navigate(ROUTES.ROLES)}
          className="p-2.5 bg-card border border-border rounded-xl hover:bg-muted transition-all shadow-sm group shrink-0"
        >
          <ChevronLeft size={20} className="text-muted-foreground group-hover:-translate-x-1 transition-transform" />
        </button>
        <div className="size-12 flex items-center justify-center rounded-(--radius-lg) bg-primary/10 shrink-0">
          <ShieldCheck className="w-7 h-7 text-primary" />
        </div>
        <div>
          <h1 className="page-title">Configure Role : {role?.name}</h1>
          <p className="page-subtitle">Manage users and permission assignments for this role.</p>
        </div>
      </div>

      {/* Tabs */}
      <Tabs
        value={activeTab}
        onValueChange={(v) => setActiveTab(v as 'users' | 'permissions')}
        className="flex flex-col"
        style={{ gap: 'var(--section-padding)' }}
      >
        <div className="border-b border-border">
          <TabsList variant="line">
            <TabsTrigger value="users" className="flex items-center gap-2">
              <Users size={16} />
              Users In Role ({roleUsers.length})
            </TabsTrigger>
            <TabsTrigger value="permissions" className="flex items-center gap-2">
              <Lock size={16} />
              Permissions Matrix
            </TabsTrigger>
          </TabsList>
        </div>

        {/* Users In Role */}
        <TabsContent value="users">
          <div className="bg-card rounded-xl border border-border shadow-sm overflow-hidden flex flex-col min-h-150 relative">
            <div className="absolute top-0 left-0 w-full h-1 bg-linear-to-r from-primary to-primary/40" />
            <div className="p-6 border-b border-border flex flex-col sm:flex-row justify-between sm:items-center gap-4 bg-muted/30 mt-1">
              <div className="flex items-center gap-3">
                <div className="p-2 bg-primary/10 text-primary rounded-lg">
                  <UserCheck size={18} />
                </div>
                <h2 className="text-lg font-bold text-foreground tracking-tight">Assigned Users</h2>
              </div>
              <div className="flex items-center gap-3">
                <div className="relative w-full sm:w-72">
                  <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" />
                  <input
                    type="text"
                    placeholder="Search users..."
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                    className="w-full pl-10 pr-4 py-2 border border-border rounded-lg text-sm bg-background text-foreground focus:outline-none focus:ring-1 focus:ring-primary/30 focus:border-primary transition"
                  />
                </div>
                <PermissionGate permission={PERMISSIONS.Role.Update} mode="hide">
                  <Button onClick={() => setAddUsersOpen(true)}>
                    <UserPlus size={16} />
                    Add Users
                  </Button>
                </PermissionGate>
              </div>
            </div>

            <div className="p-6">
              {usersLoading ? (
                <div className="flex justify-center py-24">
                  <Loader2 className="animate-spin text-primary/30" size={32} />
                </div>
              ) : usersInRole.length === 0 ? (
                <div className="py-24 flex flex-col items-center gap-4 text-muted-foreground/40">
                  <Users size={48} strokeWidth={1.5} />
                  <div className="text-center">
                    <p className="font-semibold text-foreground">
                      {searchQuery ? 'No matching users found' : 'No users in this role'}
                    </p>
                    {searchQuery && (
                      <p className="text-sm text-muted-foreground mt-1">Try a different search term</p>
                    )}
                  </div>
                </div>
              ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
                  {usersInRole.map((user) => {
                    const inactive = user.isActive === false;
                    return (
                      <div key={user.id} className={`group p-5 bg-card rounded-xl border transition-all hover:shadow-md ${inactive ? 'border-border opacity-60 hover:border-border' : 'border-border hover:border-primary/40'}`}>
                        <div className="flex items-center gap-4">
                          <div className={`relative w-11 h-11 rounded-lg flex items-center justify-center text-sm font-bold border transition-colors shrink-0 ${inactive ? 'bg-muted text-muted-foreground border-border' : 'bg-muted text-foreground border-border group-hover:bg-primary group-hover:text-primary-foreground group-hover:border-primary'}`}>
                            {user.fullName?.charAt(0) || user.email?.charAt(0).toUpperCase()}
                          </div>
                          <div className="flex flex-col min-w-0">
                            <div className="flex items-center gap-1.5 min-w-0">
                              <span className="text-sm font-bold text-foreground truncate">{user.fullName || 'Unnamed User'}</span>
                              {inactive && (
                                <span className="shrink-0 px-1.5 py-0.5 rounded text-[10px] font-bold bg-muted border border-border text-muted-foreground">
                                  Inactive
                                </span>
                              )}
                            </div>
                            <span className="text-[11px] font-medium text-muted-foreground truncate">{user.email}</span>
                          </div>
                        </div>
                        <div className="mt-4 pt-4 border-t border-border flex justify-between items-center">
                          <button
                            onClick={() => setRemoveTarget({ id: user.id, fullName: user.fullName ?? null })}
                            className="text-destructive hover:text-destructive/80 font-bold text-[11px] flex items-center gap-1 transition-colors"
                          >
                            <Trash2 size={11} /> Remove
                          </button>
                          <button
                            onClick={() => navigate(ROUTES.userProfile(user.id), { state: { from: location.pathname } })}
                            className="text-primary hover:text-primary/80 font-bold text-[11px] flex items-center gap-1 transition-colors"
                          >
                            Profile <ArrowRight size={12} />
                          </button>
                        </div>
                      </div>
                    );
                  })}
                </div>
              )}
            </div>
          </div>
        </TabsContent>

        {/* Permissions Matrix */}
        <TabsContent value="permissions">
          <div className="bg-card rounded-xl border border-border shadow-sm overflow-hidden flex flex-col min-h-175 relative">
            <div className="absolute top-0 left-0 w-full h-1 bg-linear-to-r from-primary to-primary/40" />
            <div className="p-6 border-b border-border flex flex-col sm:flex-row justify-between sm:items-center gap-4 bg-muted/30 mt-1">
              <div className="flex items-center gap-3">
                <div className="p-2 bg-primary/10 text-primary rounded-lg">
                  <Lock size={18} />
                </div>
                <h2 className="text-lg font-bold text-foreground tracking-tight">Access Control Matrix</h2>
              </div>
              <div className="flex items-center gap-2">
                {isBuiltIn ? (
                  <span className="flex items-center gap-1.5 px-3 py-1.5 rounded-md bg-muted border border-border text-[11px] font-medium text-muted-foreground">
                    <Lock size={11} />
                    Permissions are system-managed and cannot be modified
                  </span>
                ) : (
                  <>
                    {isDirty && (
                      <Button variant="outline" size="sm" onClick={handleResetPermissions} disabled={isSubmitting}>
                        <RotateCcw size={14} />
                        Reset
                      </Button>
                    )}
                    <PermissionGate permission={PERMISSIONS.RolePermission.Update} mode="hide">
                      <Button size="sm" onClick={handleSavePermissions} disabled={isSubmitting || !isDirty}>
                        {isSubmitting ? <Loader2 size={14} className="animate-spin" /> : <CheckCircle2 size={14} />}
                        Save Changes
                      </Button>
                    </PermissionGate>
                  </>
                )}
              </div>
            </div>

            <div className="flex-1 p-6">
              {(permsLoading || initialPermsLoading) ? (
                <div className="flex flex-col items-center justify-center py-40 gap-3">
                  <Loader2 className="animate-spin text-primary" size={32} />
                  <p className="text-xs font-semibold text-muted-foreground uppercase tracking-wider">Loading matrix data...</p>
                </div>
              ) : (
                <HarmonyTable<PermissionItem>
                  rows={filteredPermissionRows}
                  columns={harmonyPermissionColumns}
                  rowKeyGetter={(row) => row.id}
                  selectable={!isBuiltIn}
                  selectedRows={effectiveSelectedRows}
                  onSelectedRowsChange={handlePermissionSelectionChange}
                  isRowSelectionDisabled={(row) => adminOnlyIds.has(row.id)}
                  searchable
                  searchPlaceholder="Search permissions..."
                  filterDefs={permFilterDefs}
                  filterValues={permFilterValues}
                  onFilterChange={setPermFilterValues}
                  initialSortColumns={[
                    { columnKey: 'resource', direction: 'ASC' },
                    { columnKey: 'displayName', direction: 'ASC' },
                  ]}
                />
              )}
            </div>
          </div>
        </TabsContent>
      </Tabs>

      <AddUsersToRoleDialog
        open={addUsersOpen}
        onClose={() => setAddUsersOpen(false)}
        roleId={roleId!}
        existingUserIds={existingUserIds}
      />

      <HarmonyAlertDialog
        open={!!removeTarget}
        onOpenChange={(open) => { if (!open && !isRemoving) setRemoveTarget(null); }}
        variant="danger"
        title="Remove User from Role"
        description={`This will remove ${removeTarget?.fullName || 'this user'} from the role. They will lose any permissions granted by it.`}
        actionLabel="Remove"
        onAction={handleRemoveUser}
        isActioning={isRemoving}
      />
    </div>
  );
}
