import { useState, useMemo } from 'react';
import { Search, UserPlus, Loader2 } from 'lucide-react';
import { useQuery, useQueryClient } from '@tanstack/react-query';
import { toast } from 'sonner';
import { HarmonyDialog } from '@/components/ui/harmony-dialog';
import { Button } from '@/shadcn/components/ui/button';
import { Checkbox } from '@/shadcn/components/ui/checkbox';
import { adminService } from '@/api/auth/adminService';
import { roleService } from '@/api/auth/roleService';
import { queryKeys } from '@/lib/queryKeys';

interface AddUsersToRoleDialogProps {
  open: boolean;
  onClose: () => void;
  roleId: string;
  existingUserIds: Set<string>;
}

export function AddUsersToRoleDialog({ open, onClose, roleId, existingUserIds }: AddUsersToRoleDialogProps) {
  const queryClient = useQueryClient();
  const [search, setSearch] = useState('');
  const [selected, setSelected] = useState<Set<string>>(new Set());
  const [isSubmitting, setIsSubmitting] = useState(false);

  const pickerParams = { active: true, pageSize: 1000 };

  const { data: usersPage, isLoading } = useQuery({
    queryKey: queryKeys.admin.users(pickerParams),
    queryFn: () => adminService.getUsers(pickerParams),
    enabled: open,
  });

  const availableUsers = useMemo(() => {
    const all = (usersPage?.data ?? [])
      .filter(u => u.userType !== 'IdentityOnly' && !existingUserIds.has(u.id))
      .sort((a, b) => (a.fullName ?? '').localeCompare(b.fullName ?? ''));
    if (!search) return all;
    const q = search.toLowerCase();
    return all.filter(u =>
      u.fullName?.toLowerCase().includes(q) ||
      u.email?.toLowerCase().includes(q)
    );
  }, [usersPage, existingUserIds, search]);

  const toggleUser = (id: string) => {
    setSelected(prev => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      return next;
    });
  };

  const handleAdd = async () => {
    if (selected.size === 0) return;
    setIsSubmitting(true);
    try {
      await roleService.addUsersToRole(roleId, Array.from(selected));
      toast.success(`${selected.size} user${selected.size > 1 ? 's' : ''} added to role`);
      queryClient.invalidateQueries({ queryKey: queryKeys.roles.users(roleId) });
      setSelected(new Set());
      setSearch('');
      onClose();
    } catch {
      toast.error('Failed to add users to role');
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleClose = () => {
    setSelected(new Set());
    setSearch('');
    onClose();
  };

  return (
    <HarmonyDialog
      open={open}
      onOpenChange={(o) => { if (!o) handleClose(); }}
      title="Add Users to Role"
      description="Select one or more users to add. Users already in this role are excluded."
      size="lg"
      footerChildren={
        <div className="flex justify-end gap-3 w-full">
          <Button type="button" variant="outline" onClick={handleClose} disabled={isSubmitting}>
            Cancel
          </Button>
          <Button
            type="button"
            onClick={handleAdd}
            disabled={isSubmitting || selected.size === 0}
          >
            {isSubmitting ? <Loader2 className="animate-spin" size={16} /> : <UserPlus size={16} />}
            Add {selected.size > 0 ? `${selected.size} User${selected.size > 1 ? 's' : ''}` : 'Users'}
          </Button>
        </div>
      }
    >
      <div className="flex flex-col gap-4">
        <div className="relative">
          <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" />
          <input
            type="text"
            placeholder="Search users..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="w-full pl-10 pr-4 py-2 border border-border rounded-lg text-sm bg-background text-foreground focus:outline-none focus:ring-1 focus:ring-primary/30 focus:border-primary transition"
          />
        </div>

        {isLoading ? (
          <div className="flex justify-center py-12">
            <Loader2 className="animate-spin text-primary/30" size={28} />
          </div>
        ) : availableUsers.length === 0 ? (
          <div className="flex flex-col items-center gap-2 py-12 text-center text-muted-foreground">
            <p className="text-sm font-medium">No users available to add</p>
            {search && <p className="text-xs">Try a different search term</p>}
          </div>
        ) : (
          <div className="flex flex-col gap-0.5 max-h-80 overflow-y-auto pr-1">
            {availableUsers.map((user) => (
              <label
                key={user.id}
                className="flex items-center gap-3 p-3 rounded-lg hover:bg-muted cursor-pointer transition-colors"
              >
                <Checkbox
                  checked={selected.has(user.id)}
                  onCheckedChange={() => toggleUser(user.id)}
                />
                <div className="flex flex-col min-w-0">
                  <span className="text-sm font-semibold text-foreground truncate">{user.fullName || 'Unnamed User'}</span>
                  <span className="text-xs text-muted-foreground truncate">{user.email}</span>
                </div>
              </label>
            ))}
          </div>
        )}
      </div>
    </HarmonyDialog>
  );
}
